import React from 'react';
import JobCard from './JobCard';

const JobList = ({ jobs, variant, onSelectJob }) => {
    // Definisi gaya untuk tampilan "simple" (ala JobServices)
    const simpleGridStyle = {
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
        gap: '20px',
        maxWidth: '1200px',
        margin: '0 auto'
    };

    // Definisi gaya untuk tampilan "full" (Eksplorasi)
    const fullListStyle = {
        display: 'flex',
        flexDirection: 'column',
        gap: '20px',
        maxWidth: '900px',
        margin: '0 auto'
    };

    return (
        <div style={variant === 'simple' ? simpleGridStyle : fullListStyle}>
            {jobs.map(job => (
                <JobCard 
                    key={job.id} 
                    job={job} 
                    isFull={variant === 'full'} 
                    onClick={() => onSelectJob && onSelectJob(job)}
                />
            ))}
        </div>
    );
};

export default JobList;
